class ScienceSimulation {
    constructor(container, initialInputs) {
        this.container = container;
        this.canvas = document.createElement('canvas');
        this.ctx = this.canvas.getContext('2d');
        this.container.style.display = 'flex';
        this.container.style.alignItems = 'center';
        this.container.style.justifyContent = 'center';
        this.container.style.background = '#f8fafc';
        this.container.appendChild(this.canvas);

        this.inputGridSize = 7;
        this.inputData = this.generateInputData(this.inputGridSize);
        this.kernelData = [
            [-1, 0, 1],
            [-2, 0, 2],
            [-1, 0, 1]
        ];

        this.t = 0;
        this.update(initialInputs);
    }

    generateInputData(size) {
        const data = [];
        for (let y = 0; y < size; y++) {
            const row = [];
            for (let x = 0; x < size; x++) {
                // Create a simple vertical edge pattern
                row.push(x < size / 2 ? 0.2 : 0.8);
            }
            data.push(row);
        }
        return data;
    }

    update(inputs) {
        const { kernelSize, stride, padding, speed } = inputs;
        const dpr = window.devicePixelRatio || 1;
        const rect = this.container.getBoundingClientRect();
        this.canvas.width = rect.width * dpr;
        this.canvas.height = rect.height * dpr;
        this.canvas.style.width = rect.width + 'px';
        this.canvas.style.height = rect.height + 'px';
        this.ctx.scale(dpr, dpr);

        this.t += speed * 0.02;

        const cellSize = 35;
        const gap = 100;
        const startX = 50;
        const startY = 100;

        // Calculate output size
        const outSize = Math.floor((this.inputGridSize - kernelSize + 2 * padding) / stride) + 1;

        // Determine current scan position
        const totalSteps = outSize * outSize;
        const currentStep = Math.floor(this.t) % totalSteps;
        const outX = currentStep % outSize;
        const outY = Math.floor(currentStep / outSize);
        const inX = outX * stride - padding;
        const inY = outY * stride - padding;

        this.ctx.clearRect(0, 0, rect.width, rect.height);

        // Draw Labels
        this.ctx.font = 'bold 16px Inter, system-ui';
        this.ctx.fillStyle = '#1e293b';
        this.ctx.fillText('Input Image (7x7)', startX, startY - 40);
        this.ctx.fillText('Feature Map (' + outSize + 'x' + outSize + ')', startX + (this.inputGridSize * cellSize) + gap, startY - 40);

        // Draw Input Grid
        for (let y = 0; y < this.inputGridSize; y++) {
            for (let x = 0; x < this.inputGridSize; x++) {
                const val = this.inputData[y][x];
                this.drawCell(startX + x * cellSize, startY + y * cellSize, cellSize, val, '#cbd5e1');
            }
        }

        // Draw Padding
        if (padding > 0) {
            this.ctx.strokeStyle = '#94a3b8';
            this.ctx.setLineDash([4, 4]);
            this.ctx.strokeRect(startX - padding * cellSize, startY - padding * cellSize, (this.inputGridSize + 2 * padding) * cellSize, (this.inputGridSize + 2 * padding) * cellSize);
            this.ctx.setLineDash([]);
        }

        // Draw Kernel Highlight
        this.ctx.fillStyle = 'rgba(59, 130, 246, 0.3)';
        this.ctx.strokeStyle = '#3b82f6';
        this.ctx.lineWidth = 2;
        this.ctx.strokeRect(startX + inX * cellSize, startY + inY * cellSize, kernelSize * cellSize, kernelSize * cellSize);
        this.ctx.fillRect(startX + inX * cellSize, startY + inY * cellSize, kernelSize * cellSize, kernelSize * cellSize);

        // Draw Output Grid
        const outStartX = startX + (this.inputGridSize * cellSize) + gap;
        for (let y = 0; y < outSize; y++) {
            for (let x = 0; x < outSize; x++) {
                const isActive = x === outX && y === outY;
                const opacity = (y * outSize + x <= currentStep) ? 1 : 0.2;
                this.drawCell(outStartX + x * cellSize, startY + y * cellSize, cellSize, 0.6, isActive ? '#3b82f6' : '#64748b', opacity);
            }
        }

        // Draw Connecting Lines
        this.ctx.beginPath();
        this.ctx.moveTo(startX + inX * cellSize + kernelSize * cellSize, startY + inY * cellSize);
        this.ctx.lineTo(outStartX + outX * cellSize, startY + outY * cellSize);
        this.ctx.moveTo(startX + inX * cellSize + kernelSize * cellSize, startY + inY * cellSize + kernelSize * cellSize);
        this.ctx.lineTo(outStartX + outX * cellSize, startY + (outY + 1) * cellSize);
        this.ctx.strokeStyle = 'rgba(59, 130, 246, 0.4)';
        this.ctx.stroke();

        // Draw Legend / Info
        this.ctx.fillStyle = '#64748b';
        this.ctx.font = '12px Inter';
        this.ctx.fillText('Current Window: [' + inX + ', ' + inY + ']', startX, startY + (this.inputGridSize * cellSize) + 30);
        this.ctx.fillText('Stride: ' + stride + ' | Kernel: ' + kernelSize + 'x' + kernelSize, startX, startY + (this.inputGridSize * cellSize) + 50);
    }

    drawCell(x, y, size, val, color, opacity = 1) {
        this.ctx.globalAlpha = opacity;
        this.ctx.fillStyle = color;
        if (typeof color === 'string' && color.startsWith('#')) {
            // If it's the base grid, use the value to shade it
            if (color === '#cbd5e1') {
                const v = Math.floor(val * 255);
                this.ctx.fillStyle = `rgb(${v},${v},${v})`;
            }
        }
        this.ctx.fillRect(x + 1, y + 1, size - 2, size - 2);
        this.ctx.strokeStyle = 'rgba(0,0,0,0.05)';
        this.ctx.strokeRect(x, y, size, size);
        this.ctx.globalAlpha = 1.0;
    }
}
